"use strict";(self.webpackChunkhpcer_cluster_docs=self.webpackChunkhpcer_cluster_docs||[]).push([["1371"],{6549(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"one-spack-on-supercomputers","metadata":{"permalink":"/cluster-docs/blog/one-spack-on-supercomputers","editUrl":"https://github.com/hpcde/cluster-docs/blob/master/blog/2020-12-16-one-spack-on-supercomputers.md","source":"@site/blog/2020-12-16-one-spack-on-supercomputers.md","title":"\u5982\u4F55\u5728\u8D85\u7B97\u4E0A\u914D\u7F6ESpack","description":"\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\u6587\u6863\u4ECB\u7ECD\u4E86\u5982\u4F55\u914D\u7F6E\u3001\u4F7F\u7528 Spack\u3002\u672C\u6587\u7528\u5177\u4F53\u7684\u4F8B\u5B50\u6765\u6F14\u793A\u5982\u4F55\u5728\u8D85\u7B97\u4E0A\u914D\u7F6E Spack\uFF0C\u4E3B\u8981\u5185\u5BB9\u5982\u4E0B\uFF1A","date":"2020-12-16T00:00:00.000Z","tags":[{"inline":true,"label":"tutorial","permalink":"/cluster-docs/blog/tags/tutorial"},{"inline":true,"label":"spack","permalink":"/cluster-docs/blog/tags/spack"}],"readingTime":12.18,"hasTruncateMarker":true,"authors":[{"name":"Wang An","title":"PhD student at USTB","url":"https://github.com/alephpiece","page":{"permalink":"/cluster-docs/blog/authors/one"},"imageURL":"https://github.com/alephpiece.png","key":"one"}],"frontMatter":{"slug":"one-spack-on-supercomputers","title":"\u5982\u4F55\u5728\u8D85\u7B97\u4E0A\u914D\u7F6ESpack","authors":"one","tags":["tutorial","spack"]},"unlisted":false,"nextItem":{"title":"\u5B9E\u7528\u5DE5\u5177\uFF1ATerminal Multiplexers","permalink":"/cluster-docs/blog/one-terminal-multiplexers"}},"content":"\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\u6587\u6863\u4ECB\u7ECD\u4E86\u5982\u4F55\u914D\u7F6E\u3001\u4F7F\u7528 Spack\u3002\u672C\u6587\u7528\u5177\u4F53\u7684\u4F8B\u5B50\u6765\u6F14\u793A\u5982\u4F55\u5728\u8D85\u7B97\u4E0A\u914D\u7F6E Spack\uFF0C\u4E3B\u8981\u5185\u5BB9\u5982\u4E0B\uFF1A\\n\\n- \u51C6\u5907\u5FC5\u8981\u7684\u6570\u636E\\n- \u914D\u7F6E Spack\uFF0C\u4FEE\u6539\u914D\u7F6E\u6587\u4EF6\\n- \u6DFB\u52A0\u7F16\u8BD1\u5668\u548C\u5916\u90E8\u8F6F\u4EF6\u5305\\n- \u81EA\u5B9A\u4E49\u8F6F\u4EF6\u5305\uFF0C\u5B89\u88C5\u8F6F\u4EF6\u5305\\n- \u5BFC\u51FA\u6A21\u5757\u6587\u4EF6\\n- \u4F7F\u7528\u65B0\u5B89\u88C5\u7684\u8F6F\u4EF6\u5305\\n\\n\u672C\u6587\u6D89\u53CA\u7684\u6240\u6709\u5185\u5BB9\u57FA\u672C\u90FD\u5305\u542B\u5728\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\u6587\u6863\u548C Spack \u5B98\u65B9\u6587\u6863\u4E2D\uFF0C\u56E0\u6B64\u4E0D\u518D\u4E13\u95E8\u7ED9\u51FA\u94FE\u63A5\u3002\\n\\n{/* truncate */}\\n\\n## \u8D85\u7B97\u73AF\u5883\u8BF4\u660E\\n\\n\u4E3A\u4E86\u4FBF\u4E8E\u53D9\u8FF0\uFF0C\u6211\u4EEC\u5047\u5B9A\u8D85\u7B97\u7684\u76F8\u5173\u53C2\u6570\u3001\u73AF\u5883\u5982\u4E0B\uFF1A\\n\\n| \u53C2\u6570\u540D           | \u503C                                                           |\\n| ---------------- | ------------------------------------------------------------ |\\n| \u540D\u79F0             | S                                                            |\\n| \u67B6\u6784             | x86_64                                                       |\\n| \u64CD\u4F5C\u7CFB\u7EDF         | CentOS 7                                                     |\\n| \u6A21\u5757\u7CFB\u7EDF         | Environment Modules                                          |\\n| \u4F5C\u4E1A\u8C03\u5EA6\u7CFB\u7EDF     | Slurm                                                        |\\n| \u5DF2\u6709\u6A21\u5757         | `compiler/gcc/10.2.0`<br />`mpi/hpcx/2.5`<br />`tools/cmake/3.19.3` |\\n\\n## \u62F7\u8D1D\u5FC5\u8981\u6570\u636E\\n\\n\u6309\u7167\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\u6587\u6863\u4E2D\u7684\u8BF4\u660E\uFF0C\u6211\u4EEC\u5728\u8D85\u7B97 S \u4E0A\u5EFA\u7ACB\u5982\u4E0B\u51E0\u4E2A\u76EE\u5F55\u5E76\u62F7\u8D1D\u76F8\u5E94\u6570\u636E\uFF1A\\n\\n- `~/public/spack`\uFF1A\u5B58\u653E Spack \u4ED3\u5E93\\n- `~/public/repos/spack`\uFF1ASpack repos\uFF0C\u53EF\u80FD\u6709\u591A\u4E2A\u5B50\u76EE\u5F55\uFF0C\u5B58\u653E\u6211\u4EEC\u81EA\u5B9A\u4E49\u7684\u8F6F\u4EF6\u5305\u914D\u7F6E\u6587\u4EF6\uFF08`package.py`\uFF09\\n- `~/public/sources/spack`\uFF1ASpack mirror\uFF0C\u5B58\u653E\u6240\u6709\u8F6F\u4EF6\u5305\u7684\u6E90\u4EE3\u7801\\n- `~/public/software/spack`\uFF1ASpack \u8F6F\u4EF6\u5B89\u88C5\u8DEF\u5F84\uFF0C\u6700\u521D\u4E3A\u7A7A\u76EE\u5F55\\n- `~/.spack`\uFF1ASpack \u914D\u7F6E\u6587\u4EF6\u3001\u7F13\u5B58\u8DEF\u5F84\uFF0C\u7531 Spack \u81EA\u52A8\u521B\u5EFA\\n\\n## \u914D\u7F6E Spack \u7684\u73AF\u5883\\n\\n\u6570\u636E\u51C6\u5907\u5B8C\u6210\u540E\uFF0C\u521B\u5EFA\u4E00\u4E2A\u811A\u672C\u65B9\u4FBF\u6211\u4EEC\u542F\u7528 Spack\uFF0C\u4E0B\u9762\u4EE5 Bash \u4E3A\u4F8B\u3002\\n\\n```bash\\n#\\n# Script: setup-spack.sh\\n#\\n#!/bin/bash\\nexport SPACK_ROOT=$HOME/public/spack\\nsource $SPACK_ROOT/share/spack/setup-env.sh\\n```\\n\\n\u968F\u540E\uFF0C\u6211\u4EEC\u5148\u7533\u8BF7\u4E00\u4E2A\u8BA1\u7B97\u8282\u70B9\uFF0C\u540E\u7EED\u64CD\u4F5C\u90FD\u5728\u8BA1\u7B97\u8282\u70B9\u4E0A\u5B8C\u6210\u3002\\n\\n```bash\\n# \u7533\u8BF7\u8BA1\u7B97\u8282\u70B9\\n$ salloc -N 1 --exclusive -J spack\\n\\n# \u5047\u8BBE\u5206\u914D\u7684\u8282\u70B9\u540D\u4E3An0001\uFF0C\u8FDE\u63A5\u5230\u8BE5\u8282\u70B9\u4E0A\\n$ ssh n0001\\n\\n# \u8BBE\u7F6E\u73AF\u5883\u53D8\u91CF\\n$ source ./setup-spack.sh\\n```\\n\\n:::note\\n\u4F7F\u7528 Spack \u4E4B\u524D\uFF0C\u6700\u597D\u786E\u4FDD\u7CFB\u7EDF\u4E0A\u6709 Python 3.x\u3002\\n:::\\n\\n## \u4FEE\u6539\u914D\u7F6E\u6587\u4EF6\u4E2D\u7684\u8DEF\u5F84\\n\\n\u9996\u5148\uFF0C\u6211\u4EEC\u8981\u4FEE\u6539\u8F6F\u4EF6\u5B89\u88C5\u8DEF\u5F84\u3001mirror \u8DEF\u5F84\u548C repo \u8DEF\u5F84\u3002\\n\\n```bash\\n# \u4FEE\u6539\u8F6F\u4EF6\u5B89\u88C5\u8DEF\u5F84\\n$ spack config edit config\\n\\nconfig:\\n  install_tree:\\n    root: ~/public/software/spack\\n\\n# \u589E\u52A0\u4F18\u5148\u641C\u7D22\u7684 mirror \u8DEF\u5F84\uFF08\u9488\u5BF9\u4E0D\u80FD\u8054\u7F51\u7684\u673A\u5668\uFF09\\n$ spack config edit mirrors\\n\\nmirrors:\\n  cluster-public: file://~/public/sources/spack\\n\\n# \u589E\u52A0\u4F18\u5148\u641C\u7D22\u7684 repo \u8DEF\u5F84\uFF0C\u5982\u679C\u62F7\u8D1D\u81EA\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\uFF0C\u8981\u589E\u52A0 2 \u884C\\n$ spack config edit repos\\n\\nrepos:\\n  - ~/public/repos/spack/hpcde\\n  - ~/public/repos/spack/flipped\\n```\\n\\n## \u6DFB\u52A0\u7F16\u8BD1\u5668\\n\\n\u8D85\u7B97 S \u4E0A\u6709\u7CFB\u7EDF\u81EA\u5E26\u7684\u7F16\u8BD1\u5668\uFF0C\u4F4D\u4E8E `/usr` \u8DEF\u5F84\u3002\u5176\u4ED6\u7F16\u8BD1\u5668\u90FD\u7531\u7BA1\u7406\u5458\u5B89\u88C5\u5728\u522B\u7684\u8DEF\u5F84\uFF0C\u8981\u7528 `module load` \u52A0\u8F7D\u3002\u6211\u4EEC\u9996\u5148\u52A0\u8F7D\u7F16\u8BD1\u5668\uFF0C\u518D\u8BA9 Spack \u6765\u641C\u7D22\u3002\\n\\n```bash\\n# \u52A0\u8F7D\u8D85\u7B97\u4E0A\u5E38\u7528\u7684\u7F16\u8BD1\u5668\\n$ module load compiler/gcc/10.2.0\\n\\n# \u67E5\u627E\u7F16\u8BD1\u5668\u5E76\u6DFB\u52A0\u5230\u914D\u7F6E\u6587\u4EF6\\n$ spack compiler find\\n\\n# \u6E05\u7A7A\u73AF\u5883\uFF0C\u9632\u6B62\u5E72\u6270\u540E\u7EED\u64CD\u4F5C\\n$ module purge\\n```\\n\\n\u6267\u884C\u5B8C\u6210\u540E\uFF0C\u5E94\u8BE5\u4F1A\u6709\u81F3\u5C11\u4E00\u4E2A\u7F16\u8BD1\u5668\u88AB\u6DFB\u52A0\u5230 `compilers.yaml` \u6587\u4EF6\u4E2D\uFF0C\u6211\u4EEC\u53EF\u4EE5\u53BB\u6389\u7CFB\u7EDF\u81EA\u5E26\u7684\u4F4E\u7248\u672C\u7F16\u8BD1\u5668\uFF0C\u53EA\u4FDD\u7559\u521A\u521A\u52A0\u8F7D\u7684\u90A3\u4E2A\u3002\\n\\n\u8D85\u7B97 S \u4E0A\u7684\u7F16\u8BD1\u5668\u53EF\u80FD\u9700\u8981\u4E00\u4E9B\u989D\u5916\u7684\u73AF\u5883\u53D8\u91CF\u3001flags \u4E4B\u7C7B\uFF0C\u6211\u4EEC\u6709\u5FC5\u8981\u68C0\u67E5\u4E00\u4E0B\u539F\u672C\u7684\u6A21\u5757\u6587\u4EF6\u3002\\n\\n```bash\\n$ module show compiler/gcc/10.2.0\\n```\\n\\n\u82E5\u7684\u786E\u5B58\u5728\u73AF\u5883\u53D8\u91CF\u3001flags\uFF0C\u6211\u4EEC\u8981\u628A\u5B83\u4EEC\u6DFB\u52A0\u5230 `compilers.yaml` \u7684`environment` \u548C `flags` \u8FD9\u4E24\u4E2A\u5B57\u5178\u4E2D\u3002\\n\\n```bash\\n# \u7F16\u8F91\u914D\u7F6E\u6587\u4EF6\\n$ spack config edit compilers\\n\\n# \u82E5\u914D\u7F6E\u6587\u4EF6\u4E3A\u7A7A\u767D\uFF0C\u53EF\u80FD\u662Fscope\u7684\u4F18\u5148\u7EA7\u6709\u5F71\u54CD\uFF0C\u53EF\u4EE5\u6307\u5B9Ascope\\n# spack config --scope user compilers\\n```\\n\\n## \u6DFB\u52A0\u5916\u90E8\u8F6F\u4EF6\u5305\\n\\n\u8D85\u7B97 S \u4E0A\u6709\u4E00\u4E9B\u8F6F\u4EF6\u662F\u6211\u4EEC\u65E0\u6CD5\u81EA\u5DF1\u5B89\u88C5\u7684\uFF0C\u4F8B\u5982\uFF1A\\n\\n- `/usr` \u76EE\u5F55\u4E0B\u7684\u8F6F\u4EF6\u3002\u5B83\u4EEC\u53EF\u80FD\u662F\u5176\u4ED6\u8F6F\u4EF6\u7684\u4F9D\u8D56\u9879\uFF0C\u4E0D\u80FD\u968F\u610F\u66FF\u6362\uFF1B\\n- `CUDA`\u3001`ROCM` \u7B49\u5E73\u53F0\u76F8\u5173\u7684\u8F6F\u4EF6\u3002\u5B83\u4EEC\u7684\u5B89\u88C5\u6D89\u53CA\u786C\u4EF6\u578B\u53F7\u3001\u9A71\u52A8\u7248\u672C\uFF0C\u81EA\u5DF1\u5B89\u88C5\u975E\u5E38\u9EBB\u70E6\uFF1B\\n- `PGI` \u7B49\u7F16\u8BD1\u5668\uFF0C\u6216 `intel`\u3001`hpcx` \u7B49 MPI \u5B9E\u73B0\u3002\u5B83\u4EEC\u90FD\u662F\u5546\u7528\u8F6F\u4EF6\uFF0C\u5E76\u4E14\u53EF\u80FD\u7531\u7BA1\u7406\u5458\u5FAE\u8C03\u8FC7\u3002\\n\\n\u603B\u4E4B\uFF0C\u548C\u786C\u4EF6\u5173\u7CFB\u6BD4\u8F83\u5BC6\u5207\u7684\u8F6F\u4EF6\u90FD\u662F\u6211\u4EEC\u8981\u907F\u514D\u91CD\u65B0\u5B89\u88C5\u7684\uFF0C\u53EA\u80FD\u628A\u5B83\u4EEC\u5F53\u4F5C\u5916\u90E8\u8F6F\u4EF6\u5305\u3002\\n\\n\u6DFB\u52A0\u5916\u90E8\u8F6F\u4EF6\u5305\u65F6\uFF0C\u8981\u6CE8\u610F\u7528 `module show` \u6765\u67E5\u770B\u6A21\u5757\u6587\u4EF6\u7684\u914D\u7F6E\uFF0C\u786E\u5B9A\u4E00\u4E2A\u8F6F\u4EF6\u6709\u54EA\u4E9B\u4F9D\u8D56\u3001\u73AF\u5883\u53D8\u91CF\u9700\u8981\u8BBE\u7F6E\u3002\u6839\u636E\u6211\u4EEC\u5047\u60F3\u7684\u8D85\u7B97 S \u914D\u7F6E\uFF0C\u5916\u90E8\u8F6F\u4EF6\u5305\u5927\u6982\u6709\u4EE5\u4E0B\u51E0\u4E2A\uFF1A\\n\\n```bash\\n$ spack config edit packages\\n\\npackages:\\n  gcc:\\n    buildable: false\\n    externals:\\n    - spec: gcc@10.2.0\\n      modules:\\n      - compiler/gcc/10.2.0\\n  mpi:\\n    buildable: false\\n  hpcx:\\n    buildable: false\\n    externals:\\n    - spec: hpcx@2.5%gcc@10.2.0\\n      modules:\\n      - compiler/gcc/10.2.0\\n      - mpi/hpcx/2.5\\n  cmake:\\n    buildable: false\\n    externals:\\n    - spec: cmake@3.19.3%gcc@10.2.0\\n      modules:\\n      - tools/cmake/3.19.3\\n  gettext:\\n    buildable: false\\n    externals:\\n    - spec: gettext@system\\n      prefix: /usr\\n  curl:\\n    buildable: false\\n    externals:\\n    - spec: curl@system\\n      prefix: /usr\\n  numactl:\\n    buildable: false\\n    externals:\\n    - spec: numactl@system\\n      prefix: /usr\\n  autoconf:\\n    buildable: false\\n    externals:\\n    - spec: autoconf@system\\n      prefix: /usr\\n  automake:\\n    buildable: false\\n    externals:\\n    - spec: automake@system\\n      prefix: /usr\\n  libtool:\\n    buildable: false\\n    externals:\\n    - spec: libtool@system\\n      prefix: /usr\\n  perl:\\n    buildable: false\\n    externals:\\n    - spec: perl@system\\n      prefix: /usr\\n  openssl:\\n    buildable: false\\n    externals:\\n    - spec: openssl@system\\n      prefix: /usr\\n  openssh:\\n    buildable: false\\n    externals:\\n    - spec: openssh@system\\n      prefix: /usr\\n  binutils:\\n    buildable: false\\n    externals:\\n    - spec: binutils@system+ld+libiberty~nls\\n      prefix: /usr\\n```\\n\\n\u4ECE\u8FD9\u4E2A\u914D\u7F6E\u4E2D\u6211\u4EEC\u53EF\u4EE5\u770B\u5230\uFF0C\u6709\u4E00\u4E9B\u662F\u6211\u4EEC\u7528 `modules` \u914D\u7F6E\u7684\uFF0C\u5176\u4ED6\u90FD\u662F\u6211\u4EEC\u4ECE `/usr` \u8DEF\u5F84\u91CC\u627E\u7684\u3002\u5728 `/usr` \u8DEF\u5F84\u91CC\u7684\u8FD9\u4E9B\u90FD\u662F\u4E00\u4E9B\u6211\u4EEC\u6CA1\u6709\u5FC5\u8981\u81EA\u5DF1\u5B89\u88C5\uFF0C\u6216\u8005\u81EA\u5DF1\u5B89\u88C5\u5BB9\u6613\u51FA\u9519\u7684\u8F6F\u4EF6\uFF0C\u4F8B\u5982\uFF1A\\n\\n- `curl`\u3001`autoconf`\u3001`automake`\u3001`libtool`\u3001`perl` \u90FD\u662F\u6BD4\u8F83\u57FA\u672C\u7684\u5F00\u53D1\u5DE5\u5177\uFF0C\u4E0D\u9700\u8981\u5F88\u65B0\u7684\u7248\u672C\uFF1B\\n- `gettext` \u662F\u7528\u4E8E\u672C\u5730\u5316\u7684\u8F6F\u4EF6\uFF0C\u81EA\u5DF1\u5B89\u88C5\u53EF\u80FD\u4F1A\u6709\u95EE\u9898\uFF1B\\n- `openssl` \u662F\u7CFB\u7EDF\u7684 SSL \u8F6F\u4EF6\uFF0C\u81EA\u5DF1\u5B89\u88C5\u53EF\u80FD\u4F1A\u6709\u95EE\u9898\uFF1B\\n- `binutils` \u662F\u57FA\u672C\u7684 GNU \u5F00\u53D1\u5DE5\u5177\uFF0C\u5305\u62EC `ld`\u3001`ar` \u7B49\uFF0C\u81EA\u5DF1\u5B89\u88C5\u53EF\u80FD\u4F1A\u4E0E\u8D85\u7B97\u4E0A\u5176\u4ED6\u8F6F\u4EF6\u51B2\u7A81\u3002\u5728\u8FD9\u91CC\u4E3A\u4E86\u4FBF\u4E8E\u53D9\u8FF0\u6211\u4EEC\u76F4\u63A5\u7ED9\u5B9A\u4E3A `system`\uFF0C\u4F46\u901A\u5E38\u6211\u4EEC\u5E94\u8BE5\u7ED9\u5B9A\u7248\u672C\u53F7\u8BA9\u5176\u4ED6\u8F6F\u4EF6\u5305\u80FD\u6B63\u5E38\u5B89\u88C5\u3002\\n\\n:::tip \u7F3A\u5931\u7684\u8F6F\u4EF6\u5305\\n\\n\u76EE\u524D\u7684 Spack \u7248\u672C\uFF080.16.0\uFF09\u4E0D\u5305\u542B `hpcx` \u8FD9\u4E2A\u8F6F\u4EF6\u5305\uFF0C\u6211\u4EEC\u53EF\u4EE5\u81EA\u5B9A\u4E49\u4E00\u4E2A\u7B80\u5355\u7684 `hpcx` \u6765\u7528\u3002\u8BE6\u89C1\u672C\u6587\u540E\u7EED\u8BF4\u660E\u3002\\n\\n:::\\n\\n## \u5B89\u88C5\u65B0\u7684\u8F6F\u4EF6\u5305\\n\\n\u5916\u90E8\u8F6F\u4EF6\u5305\u914D\u7F6E\u5B8C\u6210\u540E\uFF0C\u6211\u4EEC\u5DF2\u7ECF\u5177\u5907\u5B89\u88C5\u65B0\u8F6F\u4EF6\u7684\u6240\u6709\u6761\u4EF6\u4E86\u3002\u63A5\u4E0B\u6765\uFF0C\u6211\u4EEC\u7528\u4E00\u4E2A\u811A\u672C\u6765\u6279\u91CF\u5B89\u88C5\u5982\u4E0B\u8F6F\u4EF6\uFF1A\\n\\n- `netcdf-cxx4@4.3.1`\\n- `petsc@3.14.1`\\n- `python@3.7.9`\\n- `py-numpy@1.19.4`\\n- `scorep@6.0`\\n\\n\u5728\u5B89\u88C5\u5B83\u4EEC\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u8FD8\u4F1A\u76F8\u5E94\u5730\u5B89\u88C5\u8BB8\u591A\u4F9D\u8D56\u3002\u5728\u4E0B\u9762\u7684\u811A\u672C\u4E2D\uFF0C\u6211\u4EEC\u628A\u5404\u7C7B\u4E0D\u540C\u7684\u8F6F\u4EF6\u5305\u90FD\u533A\u5206\u51FA\u6765\uFF0C\u5206\u522B\u5B89\u88C5\u3002\\n\\n```bash\\n#!/bin/bash\\n\\n# \u5916\u90E8\u8F6F\u4EF6\u5305\uFF0C\u5217\u51FA\u6765\u4FBF\u4E8E\u6211\u4EEC\u5728\u6709\u95EE\u9898\u65F6\u9488\u5BF9\u6027\u5730\u8C03\u6574\\nexternals=(\\n    gcc\\n    hpcx\\n    cmake\\n\\n    autoconf\\n    automake\\n    binutils\\n    curl\\n    gettext\\n    libtool\\n    numactl\\n    openssl\\n    perl\\n)\\n\\n# \u7F57\u5217\u6211\u4EEC\u8981\u5B89\u88C5\u7684\u8F6F\u4EF6\u5305\\ncompilers=(\'gcc@10.2.0\')\\ndevtools=(\\n    netcdf-cxx4@4.3.1\\n    petsc@3.14.1\\n    python@3.7.9\\n    py-numpy@1.19.4\\n    scorep@6.0\\n)\\n\\n# \u5B89\u88C5\u5916\u90E8\u8F6F\u4EF6\u5305\\nfor i in \\"${externals[@]}\\"\\ndo\\n    echo \\"external package: $i\\"\\n    spack install -ny --fail-fast $i\\ndone\\n\\n# \u5BF9\u4E8E\u6BCF\u4E2A\u5217\u51FA\u7684\u7F16\u8BD1\u5668\uFF0C\u5B89\u88C5\u6211\u4EEC\u9700\u8981\u7684\u8F6F\u4EF6\u5305\\nfor c in \\"${compilers[@]}\\"\\ndo\\n    for i in \\"${devtools[@]}\\"\\n    do\\n        echo \\"my package: $i%$c\\"\\n        spack install -ny --fail-fast $i%$c\\n    done\\ndone\\n```\\n\\n\u5728\u8FD9\u4E2A\u811A\u672C\u4E2D\uFF0C\u6211\u4EEC\u7528 `for` \u5FAA\u73AF\u6765\u9010\u4E2A\u5B89\u88C5\u8F6F\u4EF6\u5305\uFF0C\u8FD9\u6837\u65B9\u4FBF\u6211\u4EEC\u505A\u4E00\u4E9B\u989D\u5916\u7684\u64CD\u4F5C\uFF08\u6BD4\u5982\u6253\u5370\u63D0\u793A\u4FE1\u606F\uFF09\u3002\u6267\u884C\u5B8C\u6210\u540E\uFF0C\u6240\u6709\u8F6F\u4EF6\u548C\u4F9D\u8D56\u90FD\u5DF2\u6B63\u786E\u5B89\u88C5\uFF0C\u6211\u4EEC\u53EF\u4EE5\u9009\u62E9\u6E05\u7406\u4E0D\u5FC5\u8981\u7684\u6587\u4EF6\u3002\\n\\n```bash\\n# \u6E05\u7406\u53EF\u80FD\u5B58\u5728\u7684\u4E34\u65F6\u6587\u4EF6\\n$ spack clean\\n\\n# \u6E05\u7406\u4E0D\u5FC5\u8981\u7684\u4F9D\u8D56\u9879\\n$ spack gc\\n```\\n\\n## \u5BFC\u51FA\u6A21\u5757\u6587\u4EF6\\n\\n\u4F7F\u7528 Spack \u5B89\u88C5\u4E86\u8F6F\u4EF6\u5305\u540E\uFF0C\u6211\u4EEC\u8FD8\u53EA\u80FD\u7528 `spack load` \u52A0\u8F7D\u3002\u5728\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\u6587\u6863\u4E2D\u6709\u63D0\u5230\uFF0C\u8FD9\u79CD\u52A0\u8F7D\u65B9\u5F0F\u6BD4 `module load` \u8981\u6162\u5F88\u591A\uFF0C\u4E14\u4E0E `module load` \u6DF7\u7528\u5BB9\u6613\u51FA\u95EE\u9898\u3002\\n\\n\u7531\u4E8E\u6211\u4EEC\u4E0D\u53EF\u907F\u514D\u5730\u8981\u4F7F\u7528\u8D85\u7B97 S \u4E0A\u7684 Environment Modules\uFF0C\u6211\u4EEC\u63A5\u4E0B\u6765\u628A\u521A\u521A\u5B89\u88C5\u7684\u6240\u6709\u8F6F\u4EF6\u5305\u90FD\u5BFC\u51FA\u4E3A\u6A21\u5757\u6587\u4EF6\u3002\u4E3A\u6B64\uFF0C\u5148\u8C03\u6574\u914D\u7F6E\u6587\u4EF6\uFF0C\u53EA\u5141\u8BB8\u4E00\u4E9B\u8F6F\u4EF6\u5305\u88AB\u5BFC\u51FA\u4E3A\u6A21\u5757\uFF0C\u540C\u65F6\u4FEE\u6539\u4E00\u4E0B\u6A21\u5757\u7684\u547D\u540D\u89C4\u5219\u3002\\n\\n```bash\\n$ spack config edit modules\\n\\nmodules:\\n  tcl:\\n    hash_length: 0\\n    verbose: True\\n    blacklist:\\n      - autoconf\\n      - automake\\n      - curl\\n      - gettext\\n      - libtool\\n      - numactl\\n      - openssl\\n      - openssh\\n      - perl\\n    all:\\n      conflict:\\n        - \'{name}\'\\n      environment:\\n        set:\\n          \'{name}_ROOT\': \'{prefix}\'\\n    projections:\\n      all:      \'{name}/{version}/{compiler.name}-{compiler.version}\'\\n      ^mpi:     \'{name}/{version}/{^mpi.name}-{^mpi.version}-{compiler.name}-{compiler.version}\'\\n    ^python:\\n      autoload: direct\\n```\\n\\n\u8BE5\u914D\u7F6E\u6587\u4EF6\u4E2D\u5404\u5BF9\u8C61\u7684\u542B\u4E49\u5982\u4E0B\uFF1A\\n\\n- `tcl`\uFF1A\u8868\u793A\u6211\u4EEC\u63A5\u4E0B\u6765\u7684\u914D\u7F6E\u90FD\u662F\u9488\u5BF9 Tcl \u6A21\u5757\u6587\u4EF6\u7684\uFF1B\\n- `hash_length`\uFF1A\u6A21\u5757\u6587\u4EF6\u540D\u79F0\u4E2D hash \u503C\u7684\u957F\u5EA6\uFF1B\\n- `verbose`\uFF1A\u5F53\u6A21\u5757\u6709 `autoload` \u6307\u5B9A\u7684\u4F9D\u8D56\u65F6\uFF0C\u8F93\u51FA\u63D0\u793A\u4FE1\u606F\uFF1B\\n- `blacklist`\uFF1A\u7981\u6B62\u4E3A\u8FD9\u4E9B\u6A21\u5757\u751F\u6210\u6587\u4EF6\uFF0C\u6211\u4EEC\u628A `/usr` \u91CC\u627E\u5230\u7684\u90FD\u5C4F\u853D\u6389\uFF1B\\n- `all`\uFF1A\u5BF9\u6240\u6709 Tcl \u6A21\u5757\u751F\u6548\u7684\u8BBE\u7F6E\uFF1B\\n- `conflict`\uFF1A\u5728\u6A21\u5757\u6587\u4EF6\u4E2D\u589E\u52A0 `conflict`\uFF1B\\n- `environment`\uFF1A\u5728\u6A21\u5757\u6587\u4EF6\u4E2D\u8BBE\u7F6E\u7279\u5B9A\u73AF\u5883\u53D8\u91CF\uFF0C\u5728\u6B64\u6211\u4EEC\u8BBE\u5B9A\u8BF8\u5982 `PETSC_ROOT` \u4E4B\u7C7B\u7684\u53D8\u91CF\uFF1B\\n- `projections`\uFF1A\u8C03\u6574\u8F6F\u4EF6\u5305\u5230\u6A21\u5757\u6587\u4EF6\u7684\u6620\u5C04\u89C4\u5219\uFF1B\\n- `autoload`\uFF1A\u6307\u660E\u6EE1\u8DB3\u7279\u5B9A\u6761\u4EF6\u7684\u6A21\u5757\u9700\u8981\u52A0\u8F7D\u7684\u4F9D\u8D56\uFF0C\u8FD9\u91CC\u6211\u4EEC\u8BA9\u6240\u6709\u4F9D\u8D56\u4E8E `python` \u7684\u6A21\u5757\u90FD\u52A0\u8F7D\u4F9D\u8D56\u9879\u3002\\n\\n\u914D\u7F6E\u5B8C\u6210\u540E\uFF0C\u6267\u884C\u547D\u4EE4\u6765\u751F\u6210\u6A21\u5757\u6587\u4EF6\uFF1A\\n\\n```bash\\n# \u6E05\u7A7A\u4EE5\u524D\u7684\u6A21\u5757\u6587\u4EF6\uFF0C\u751F\u6210\u65B0\u7684\u6A21\u5757\u6587\u4EF6\\n$ spack module tcl refresh --delete-tree\\n```\\n\\n\u968F\u540E\u4F7F\u7528\u547D\u4EE4\u6765\u542F\u7528 Spack \u6A21\u5757\u6587\u4EF6\u7684\u8DEF\u5F84\uFF0C\u8BE5\u8DEF\u5F84\u53EF\u4EE5\u5728 `config.yaml` \u4E2D\u4FEE\u6539\u3002\u5728\u8FD9\u91CC\u6211\u4EEC\u4F7F\u7528\u9ED8\u8BA4\u8DEF\u5F84\u3002\\n\\n```bash\\n# \u542F\u7528\u6A21\u5757\u641C\u7D22\u8DEF\u5F84\\n$ module use $SPACK_ROOT/share/spack/modules\\n\\n# \u5982\u679C\u8BE5\u8DEF\u5F84\u5E95\u4E0B\u8FD8\u6709\u4EE5\u67B6\u6784\u547D\u540D\u7684\u76EE\u5F55\uFF0C\u4E3A\u4E86\u907F\u514D\u6A21\u5757\u6587\u4EF6\u540D\u8FC7\u957F\uFF0C\u6211\u4EEC\u53EF\u4EE5\u7528\u4EE5\u4E0B\u547D\u4EE4\\n# module use $SPACK_ROOT/share/spack/modules/linux-centos7-x86_64\\n```\\n\\n\u6A21\u5757\u6587\u4EF6\u7684\u914D\u7F6E\u90FD\u5B8C\u6210\u540E\uFF0C\u6211\u4EEC\u5C31\u53EF\u4EE5\u50CF\u52A0\u8F7D\u8D85\u7B97 S \u4E0A\u5DF2\u6709\u7684\u6A21\u5757\u4E00\u6837\u52A0\u8F7D\u65B0\u5B89\u88C5\u7684\u6A21\u5757\u4E86\u3002\\n\\n## \u52A0\u8F7D\u6A21\u5757\\n\\n\u6211\u4EEC\u53EF\u4EE5\u76F4\u63A5\u7528 `module load` \u52A0\u8F7D\u6A21\u5757\uFF0C\u4F46\u8FD9\u79CD\u65B9\u5F0F\u53EF\u80FD\u4F1A\u8BA9\u52A0\u8F7D\u7684\u6A21\u5757\u7F3A\u5C11\u4E00\u4E9B\u4F9D\u8D56\u3002Spack v0.16.0 \u8FD8\u4E0D\u80FD\u5F88\u597D\u5730\u5904\u7406\u6A21\u5757\u7684\u4F9D\u8D56\u5173\u7CFB\uFF0C\u6211\u4EEC\u8981\u4E48\u4FEE\u6539 Spack \u7684\u6A21\u5757\u6587\u4EF6 `templates`\uFF0C\u8981\u4E48\u5C31\u8BA9 Spack \u4E3A\u6211\u4EEC\u751F\u6210\u52A0\u8F7D\u6A21\u5757\u7528\u7684\u547D\u4EE4\u3002\u8FD9\u91CC\u6211\u4EEC\u9009\u62E9\u540E\u8005\u3002\\n\\n```bash\\n# \u751F\u6210\u4E00\u4E2A\u811A\u672C\uFF0C\u5176\u4E2D\u4F1A\u5305\u542B\u5F88\u591Amodule load\u547D\u4EE4\\n$ echo \'#!/bin/bash\' > env.sh\\n$ spack module tcl loads -r petsc py-numpy >> env.sh\\n$ chmod u+x env.sh\\n\\n# \u52A0\u8F7Dpetsc\u548Cpy-numpy\\n$ source ./env.sh\\n```\\n\\n## \u9644\uFF1A\u81EA\u5B9A\u4E49\u8F6F\u4EF6\u5305\\n\\n\u5728\u6DFB\u52A0\u5916\u90E8\u8F6F\u4EF6\u5305\u6216\u8005\u5B89\u88C5\u65B0\u8F6F\u4EF6\u5305\u65F6\uFF0C\u6211\u4EEC\u53EF\u80FD\u4F1A\u9047\u5230 Spack \u4E0D\u80FD\u8BC6\u522B\u7684\u540D\u79F0\uFF0C\u6BD4\u5982 `hpcx`\u3002\u9047\u5230\u8FD9\u79CD\u60C5\u51B5\u5927\u81F4\u6709\u4EE5\u4E0B\u51E0\u79CD\u5904\u7406\u65B9\u5F0F\uFF1A\\n\\n- \u5B83\u53EF\u80FD\u53EB\u4E0D\u540C\u540D\u5B57\uFF0C\u6211\u4EEC\u53EF\u4EE5\u4F7F\u7528 `spack list` \u6309\u901A\u914D\u7B26\u641C\u7D22\uFF1B\\n- \u5728 Spack \u6587\u6863\u3001GitHub \u6216\u5176\u4ED6\u7F51\u7AD9\u4E0A\u641C\u7D22\u8BE5\u8F6F\u4EF6\u5305\u7684\u914D\u7F6E\u6587\u4EF6\uFF0C\u627E\u5230\u4E86\u53EF\u4EE5\u76F4\u63A5\u7528\uFF1B\\n- \u81EA\u5DF1\u5B9A\u4E49\u8BE5\u8F6F\u4EF6\u5305\u3002\\n\\n\u4E0B\u9762\u4EE5 `hpcx` \u4E3A\u4F8B\u6F14\u793A\u5982\u4F55\u81EA\u5B9A\u4E49\u8F6F\u4EF6\u5305\u5E76\u8BBE\u7F6E\u8FD0\u884C\u65F6\u7684\u73AF\u5883\u53D8\u91CF\u3002\u5047\u8BBE\u8D85\u7B97 S \u4E0A\u5B89\u88C5\u7684 `hpcx` \u6709\u5982\u4E0B\u76EE\u5F55\u7ED3\u6784\uFF1A\\n\\n```\\nhpcx/\\n|- gcc-10.2.0/\\n|- hcoll/\\n|- sharp/\\n`- ucx/\\n```\\n\\n\u7B80\u5355\u8D77\u89C1\uFF0C\u6211\u4EEC\u628A `hpcx` \u5F53\u4F5C\u57FA\u4E8E `openmpi` \u7684\u53E6\u4E00\u79CD `mpi`\uFF0C\u5E76\u4E14\u4E0D\u8003\u8651\u5B83\u7684\u8BF8\u5982 `ucx`\u3001`hcoll` \u4E4B\u7C7B\u7684\u4F9D\u8D56\u9879\u3002\u8003\u8651\u5230\u6211\u4EEC\u53EA\u60F3\u8981\u4E00\u4E2A\u5916\u90E8\u8F6F\u4EF6\u5305\uFF0C\u4E0D\u4F1A\u76F4\u63A5 build \u5B83\uFF0C\u6211\u4EEC\u8981\u505A\u7684\u4E8B\u60C5\u53D8\u5F97\u5F88\u7B80\u5355\uFF1A\\n\\n- \u521B\u5EFA\u4E00\u4E2A\u540D\u4E3A `hpcx` \u7684 bundle package\uFF1B\\n- \u5728 `package.py` \u4E2D\uFF0C\u8BA9 `hpcx` \u4F9D\u8D56\u4E8E `openmpi`\uFF0C\u5E76\u4E14\u63D0\u4F9B `mpi`\uFF1B\\n- \u5728 `package.py` \u4E2D\uFF0C\u8BBE\u7F6E build\u3001run \u7B49\u5404\u9636\u6BB5\u6240\u7528\u7684\u73AF\u5883\u3002\\n\\n\u9996\u5148\u662F\u521B\u5EFA\uFF0C\u5728\u521B\u5EFA\u65F6\u8981\u6307\u660E repo \u7684\u4F4D\u7F6E\u4EE5\u4FBF\u4E8E\u7EDF\u4E00\u7BA1\u7406\uFF1A\\n\\n```bash\\n$ spack create -r ~/public/repos/spack/ -t bundle -n hpcx\\n```\\n\\n\u63A5\u7740\u4FEE\u6539 `package.py`\uFF1A\\n\\n```python\\nfrom spack import *\\n\\nclass Hpcx(BundlePackage):\\n    \\"\\"\\"Mellanox HPC-X ScalableHPC Software Toolkit\\"\\"\\"\\n    homepage = \\"https://www.mellanox.com/products/hpc-x-toolkit\\"\\n    \\n    executables = [\'^ompi_info$\']\\n    \\n    version(\'2.4.1\')\\n\\n    provides(\'mpi\')\\n    provides(\'mpi@:3.0\', when=\'@2.0.0:\')\\n    depends_on(\'openmpi\')\\n    \\n    def setup_run_environment(self, env):\\n        import os\\n\\n        # Set user environment manually.\\n        hpcx_home       = os.path.dirname(self.prefix)\\n        hpcx_mpi_dir    = self.prefix\\n        hpcx_oshmem_dir = self.prefix\\n        hpcx_hcoll_dir  = join_path(hpcx_home, \'hcoll\')\\n        hpcx_sharp_dir  = join_path(hpcx_home, \'sharp\')\\n        hpcx_ucx_dir    = join_path(hpcx_home, \'ucx\')\\n\\n        for d in [hpcx_hcoll_dir, hpcx_sharp_dir, hpcx_ucx_dir]:\\n            env.prepend_path(\'PATH\',            join_path(d, \'bin\'))\\n            env.prepend_path(\'CPATH\',           join_path(d, \'include\'))\\n            env.prepend_path(\'LIBRARY_PATH\',    join_path(d, \'lib\'))\\n            env.prepend_path(\'LD_LIBRARY_PATH\', join_path(d, \'lib\'))\\n            \\n        # Dependency directories\\n        env.set(\'HPCX_HCOLL_DIR\', hpcx_hcoll_dir)\\n        env.set(\'HPCX_SHARP_DIR\', hpcx_sharp_dir)\\n        env.set(\'HPCX_UCX_DIR\',   hpcx_ucx_dir)\\n\\n        # Home directories\\n        homes = [\'HPCX_DIR\', \'HPCX_HOME\']\\n        for home in homes:\\n            env.set(home, hpcx_home)\\n\\n        mpi_homes = [\'HPCX_MPI_DIR\', \'HPCX_MPI_DIR\', \'OMPI_HOME\', \'MPI_HOME\']\\n        for mpi_home in mpi_homes:\\n            env.set(mpi_home, hpcx_mpi_dir)\\n\\n        oshmem_homes = [\'HPCX_OSHMEM_DIR\', \'OSHMEM_HOME\', \'SHMEM_HOME\']\\n        for oshmem_home in oshmem_homes:\\n            env.set(oshmem_home, hpcx_oshmem_dir)\\n\\n        # Because MPI is both a runtime and a compiler, we have to setup the\\n        # compiler components as part of the run environment.\\n        env.set(\'MPICC\',  join_path(self.prefix.bin, \'mpicc\'))\\n        env.set(\'MPICXX\', join_path(self.prefix.bin, \'mpic++\'))\\n        env.set(\'MPIF77\', join_path(self.prefix.bin, \'mpif77\'))\\n        env.set(\'MPIF90\', join_path(self.prefix.bin, \'mpif90\'))\\n\\n    def setup_dependent_build_environment(self, env, dependent_spec):\\n        # Duplicate environment variables to avoid Spack warnings.\\n        env.set(\'MPICC\',  join_path(self.prefix.bin, \'mpicc\'))\\n        env.set(\'MPICXX\', join_path(self.prefix.bin, \'mpic++\'))\\n        env.set(\'MPIF77\', join_path(self.prefix.bin, \'mpif77\'))\\n        env.set(\'MPIF90\', join_path(self.prefix.bin, \'mpif90\'))\\n\\n        # Use the spack compiler wrappers under MPI\\n        env.set(\'OMPI_CC\',  spack_cc)\\n        env.set(\'OMPI_CXX\', spack_cxx)\\n        env.set(\'OMPI_FC\',  spack_fc)\\n        env.set(\'OMPI_F77\', spack_f77)\\n\\n        # See https://www.open-mpi.org/faq/?category=building#installdirs\\n        for suffix in [\'PREFIX\', \'EXEC_PREFIX\', \'BINDIR\', \'SBINDIR\',\\n                       \'LIBEXECDIR\', \'DATAROOTDIR\', \'DATADIR\', \'SYSCONFDIR\',\\n                       \'SHAREDSTATEDIR\', \'LOCALSTATEDIR\', \'LIBDIR\',\\n                       \'INCLUDEDIR\', \'INFODIR\', \'MANDIR\', \'PKGDATADIR\',\\n                       \'PKGLIBDIR\', \'PKGINCLUDEDIR\']:\\n            env.unset(\'OPAL_%s\' % suffix)\\n\\n    def setup_dependent_package(self, module, dependent_spec):\\n        self.spec.mpicc  = join_path(self.prefix.bin, \'mpicc\')\\n        self.spec.mpicxx = join_path(self.prefix.bin, \'mpic++\')\\n        self.spec.mpifc  = join_path(self.prefix.bin, \'mpif90\')\\n        self.spec.mpif77 = join_path(self.prefix.bin, \'mpif77\')\\n        self.spec.mpicxx_shared_libs = [\\n            join_path(self.prefix.lib, \'libmpi_cxx.{0}\'.format(dso_suffix)),\\n            join_path(self.prefix.lib, \'libmpi.{0}\'.format(dso_suffix))\\n        ]\\n```\\n\\n\u5728\u8FD9\u4E2A\u914D\u7F6E\u6587\u4EF6\u4E2D\uFF0C\u6211\u4EEC\u589E\u52A0\u4E86\u4E00\u4E9B\u8BED\u53E5\u8BA9 `hpcx` \u80FD\u50CF `openmpi` \u4E00\u6837\u88AB\u4F7F\u7528\u3002\u5176\u4E2D\uFF1A\\n\\n- `executables` \u7528\u4E8E\u63D0\u4F9B\u53EF\u6267\u884C\u6587\u4EF6\u8BA9 Spack \u80FD\u591F\u8BC6\u522B\uFF1B\\n- `provides` \u7528\u4E8E\u63D0\u4F9B virtual package \u7ED9\u5176\u4ED6\u8F6F\u4EF6\u5305\u4F7F\u7528\uFF1B\\n- `env` \u662F\u8868\u793A\u7528\u6237\u73AF\u5883\u7684\u5BF9\u8C61\uFF0C\u53EF\u4EE5\u64CD\u4F5C\u73AF\u5883\u53D8\u91CF\uFF1B\\n- `setup_run_environment` \u662F\u8BBE\u7F6E runtime \u73AF\u5883\u7684\u65B9\u6CD5\uFF0C\u5728\u52A0\u8F7D\u3001\u5378\u8F7D `hpcx` \u65F6\u4F1A\u88AB\u6267\u884C\uFF1B\\n- `setup_dependent_build_environment` \u662F\u8BBE\u7F6E build-time \u73AF\u5883\u7684\u65B9\u6CD5\uFF0C\u4F1A\u5F71\u54CD\u4F9D\u8D56\u4E8E `hpcx` \u7684\u8F6F\u4EF6\u5305\uFF1B\\n- `setup_dependent_package` \u4E5F\u662F\u8BBE\u7F6E build-time \u73AF\u5883\u7684\u65B9\u6CD5\uFF0C\u5F71\u54CD\u4F9D\u8D56\u4E8E `hpcx` \u7684\u8F6F\u4EF6\u5305\u3002\\n\\n\u5728 `setup_run_environment` \u4E2D\u6211\u4EEC\u8BBE\u7F6E\u4E86\u5F88\u591A\u73AF\u5883\u53D8\u91CF\uFF0C\u5982\u679C\u8FD8\u6709\u5176\u4ED6\u4E0E\u8D85\u7B97 S \u7F51\u7EDC\u76F8\u5173\u7684\u73AF\u5883\u9700\u8981\u8BBE\u7F6E\uFF0C\u4E5F\u53EF\u4EE5\u6DFB\u52A0\u5728\u8BE5\u65B9\u6CD5\u4E2D\u3002\\n\\n:::note\\n\u8FD9\u91CC\u914D\u7F6E\u7684 `hpcx` \u662F\u7ED9\u5916\u90E8\u8F6F\u4EF6\u5305\u4F7F\u7528\u7684\uFF0C\u6240\u4EE5\u91CC\u9762\u6CA1\u6709\u7ED9\u5B9A\u5176\u4ED6\u4F9D\u8D56\u9879\u3002\\n:::"},{"id":"one-terminal-multiplexers","metadata":{"permalink":"/cluster-docs/blog/one-terminal-multiplexers","editUrl":"https://github.com/hpcde/cluster-docs/blob/master/blog/2020-12-12-one-terminal-multiplexers.md","source":"@site/blog/2020-12-12-one-terminal-multiplexers.md","title":"\u5B9E\u7528\u5DE5\u5177\uFF1ATerminal Multiplexers","description":"\u4F7F\u7528\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\u65F6\uFF0C\u6211\u4EEC\u53EF\u80FD\u5076\u5C14\u4F1A\u9047\u5230\u65AD\u5F00\u8FDE\u63A5\u7684\u60C5\u51B5\uFF0C\u53EF\u80FD\u662F\u4E3B\u52A8\u65AD\u5F00SSH\uFF0C\u4E5F\u53EF\u80FD\u662F\u7F51\u7EDC\u4E0D\u7A33\u5B9A\u3002\u65E0\u8BBA\u600E\u6837\uFF0C\u91CD\u65B0\u8FDE\u63A5\u540E\u4E0D\u4F1A\u81EA\u52A8\u6062\u590D\u4E0A\u4E00\u6B21\u7684\u5DE5\u4F5C\uFF08\u6240\u5728\u7684\u8DEF\u5F84\u3001\u73AF\u5883\u53D8\u91CF\u3001\u6253\u5F00\u7684\u6587\u4EF6\u7B49\uFF09\u3002","date":"2020-12-12T00:00:00.000Z","tags":[{"inline":true,"label":"tool","permalink":"/cluster-docs/blog/tags/tool"},{"inline":true,"label":"screen","permalink":"/cluster-docs/blog/tags/screen"},{"inline":true,"label":"tmux","permalink":"/cluster-docs/blog/tags/tmux"}],"readingTime":5.47,"hasTruncateMarker":true,"authors":[{"name":"Wang An","title":"PhD student at USTB","url":"https://github.com/alephpiece","page":{"permalink":"/cluster-docs/blog/authors/one"},"imageURL":"https://github.com/alephpiece.png","key":"one"}],"frontMatter":{"slug":"one-terminal-multiplexers","title":"\u5B9E\u7528\u5DE5\u5177\uFF1ATerminal Multiplexers","authors":"one","tags":["tool","screen","tmux"]},"unlisted":false,"prevItem":{"title":"\u5982\u4F55\u5728\u8D85\u7B97\u4E0A\u914D\u7F6ESpack","permalink":"/cluster-docs/blog/one-spack-on-supercomputers"},"nextItem":{"title":"\u4F7F\u7528\u96C6\u7FA4\u4E0A\u5B89\u88C5\u7684BOUT++\u5E93","permalink":"/cluster-docs/blog/one-bout-dev-usage"}},"content":"\u4F7F\u7528\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\u65F6\uFF0C\u6211\u4EEC\u53EF\u80FD\u5076\u5C14\u4F1A\u9047\u5230\u65AD\u5F00\u8FDE\u63A5\u7684\u60C5\u51B5\uFF0C\u53EF\u80FD\u662F\u4E3B\u52A8\u65AD\u5F00SSH\uFF0C\u4E5F\u53EF\u80FD\u662F\u7F51\u7EDC\u4E0D\u7A33\u5B9A\u3002\u65E0\u8BBA\u600E\u6837\uFF0C\u91CD\u65B0\u8FDE\u63A5\u540E\u4E0D\u4F1A\u81EA\u52A8\u6062\u590D\u4E0A\u4E00\u6B21\u7684\u5DE5\u4F5C\uFF08\u6240\u5728\u7684\u8DEF\u5F84\u3001\u73AF\u5883\u53D8\u91CF\u3001\u6253\u5F00\u7684\u6587\u4EF6\u7B49\uFF09\u3002\\n\\n\u4E3A\u4E86\u4FDD\u5B58\u5DE5\u4F5C\uFF0C\u4FBF\u4E8E\u91CD\u8FDE\u540E\u7EE7\u7EED\uFF0C\u6211\u4EEC\u53EF\u4EE5\u8BA9\u81EA\u5DF1\u7684\u7A0B\u5E8F\u6216\u8005 shell \u5728\u540E\u53F0\u4E00\u76F4\u8FD0\u884C\u3002\u4FDD\u6301\u7A0B\u5E8F\u540E\u53F0\u8FD0\u884C\u7684\u65B9\u5F0F/\u5DE5\u5177\u6709\u5F88\u591A\uFF0C\u672C\u6587\u7B80\u5355\u4ECB\u7ECD\u4EE5\u4E0B\u51E0\u79CD\uFF1A\\n\\n- `nohup` \u548C `&`\\n- `screen`\\n- `tmux`\\n\\n{/* truncate */}\\n\\n## \u540E\u53F0\u8FD0\u884C\u7A0B\u5E8F\uFF1Anohup \u548C &\\n\\n\u53C2\u8003\uFF1A\\n\\n- [Wikipedia - nohup](https://en.wikipedia.org/wiki/Nohup)\\n\\nLinux\u4E0A\u5E38\u7528\u7684\u540E\u53F0\u6267\u884C\u7A0B\u5E8F\u7684\u547D\u4EE4\u662F `nohup`\uFF0C\u5B83\u7684\u529F\u80FD\u662F\u65E0\u89C6 hangup \u4FE1\u53F7\uFF0C\u4E5F\u5C31\u662F\u5728 shell \u9000\u51FA\u65F6\u4E0D\u4F1A\u81EA\u52A8\u88AB\u6302\u65AD\u3002\u8BE5\u547D\u4EE4\u9ED8\u8BA4\u4F1A\u628A\u539F\u672C\u5230\u6807\u51C6\u8F93\u51FA\u7684\u4E1C\u897F\u91CD\u5B9A\u5411\u5230\u4E00\u4E2A\u6587\u4EF6\u3002\\n\\n```bash\\n$ nohup ping nodedata\\nnohup: ignoring input and appending output to \u2018nohup.out\u2019\\n```\\n\\n\u6267\u884C\u8BE5\u547D\u4EE4\u540E\uFF0C\u9000\u51FA shell \u4E0D\u4F1A\u4E2D\u65AD\u5B83\u3002\u5B9E\u9645\u4E0A\uFF0C\u5B83\u5DF2\u7ECF\u4E0D\u518D\u4F9D\u8D56\u4E8E\u4EFB\u4F55 pts \u4E86\u3002\u4E0D\u8FC7\uFF0C\u6211\u4EEC\u76F4\u63A5\u5728\u5F53\u524Dshell\u6267\u884C\u540E\uFF08*foreground*\uFF09\uFF0C\u628A\u81EA\u5DF1\u7684 shell \u4E5F\u963B\u585E\u4E86\uFF0C\u56E0\u6B64\u6211\u4EEC\u8981\u628A\u7A0B\u5E8F\u653E\u5728\u540E\u53F0\uFF08*background*\uFF09\u3002\\n\\n```bash\\n$ ping nodedata &\\n```\\n\\n\u6267\u884C\u8BE5\u547D\u4EE4\u540E\uFF0C\u4F1A\u4EA7\u751F\u4E00\u4E2A subshell \u6765\u6267\u884C `ping nodedata`\uFF0C\u8F93\u51FA\u4ECD\u7136\u662F\u6807\u51C6\u8F93\u51FA\uFF0C\u6240\u4EE5\u4F1A\u51FA\u73B0\u8FD9\u6837\u7684\u60C5\u51B5\uFF1A\u5C4F\u5E55\u4E0D\u65AD\u5730\u6253\u5370\u4E1C\u897F\u51FA\u6765\uFF0C\u4F46\u81EA\u5DF1\u8FD8\u662F\u80FD\u6B63\u5E38\u6572\u5176\u4ED6\u547D\u4EE4\u3002\\n\\n\u4F5C\u4E3A\u540E\u53F0\u8FD0\u884C\u7684\u8FDB\u7A0B\uFF0C\u76F4\u63A5\u7528\u7EC4\u5408\u952E `Control + c` \u662F\u65E0\u6CD5\u7EC8\u6B62\u7684\u3002\u901A\u5E38\u6709\u4E24\u79CD\u65B9\u6CD5\u7528\u4E8E\u7EC8\u6B62\u4E00\u4E2A\u540E\u53F0\u6267\u884C\u7684\u7A0B\u5E8F\uFF1A\\n\\n- \u7528 `ps` \u627E\u5230\u8FDB\u7A0B\u53F7\uFF0C\u7528 `kill` \u76F4\u63A5\u53D1\u9001\u7EC8\u6B62\u4FE1\u53F7\uFF1B\\n- \u7528 `fg` \u628A\u540E\u53F0\u7A0B\u5E8F\u8C03\u5230\u5230\u524D\u9762\uFF0C\u518D `Control + c` \u7EC8\u6B62\u3002\\n\\n\u4E86\u89E3 `nohup` \u548C `&` \u4EE5\u540E\uFF0C\u6211\u4EEC\u53EF\u4EE5\u7EC4\u5408\u4E24\u8005\uFF0C\u5B9E\u73B0\u540E\u53F0\u8FD0\u884C\u4E00\u4E2A\u4E0D\u4F9D\u8D56\u4E8E\u5F53\u524D shell \u7684\u7A0B\u5E8F\u3002\\n\\n```bash\\n$ nohup ping nodedata &\\n```\\n\\n\u6267\u884C\u8BE5\u547D\u4EE4\u540E\uFF0C\u4ECD\u7136\u53EF\u4EE5\u5728\u5F53\u524Dshell\u505A\u5176\u4ED6\u4E8B\u60C5\uFF0C\u56E0\u4E3A `&` \u628A\u7A0B\u5E8F\u8F6C\u5165\u540E\u53F0\uFF0C\u800C `nohup` \u91CD\u5B9A\u5411\u4E86\u8F93\u51FA\u3002\u4E5F\u53EF\u4EE5\u7ACB\u9A6C\u9000\u51FA\uFF0C\u56E0\u4E3A `nohup` \u4F1A\u65E0\u89C6SIGHUP\u4FE1\u53F7\u3002\\n\\n## Terminal multiplexers\\n\\n\u53C2\u8003\uFF1A\\n\\n- [Wikipedia - Terminal multiplexer](https://en.wikipedia.org/wiki/Terminal_multiplexer)\\n\\n\u7EC8\u7AEF\u591A\u8DEF\u590D\u7528\u5668\uFF08terminal multiplexers\uFF09\u5C31\u662F\u4E00\u79CD\u521B\u5EFA\u591A\u4E2A\u4F2A\u7EC8\u7AEF\uFF08\u4F1A\u8BDD\uFF09\u7684\u7A0B\u5E8F\uFF0C\u8FBE\u5230\u7C7B\u4F3C\u4E8E\u201C\u591A\u8DEF\u590D\u7528\u201D\u7684\u72B6\u6001\u3002\u76F8\u6BD4\u4E8E `nohup` \u901A\u5E38\u53EA\u7528\u4E8E\u8DD1\u5355\u4E2A\u7A0B\u5E8F\uFF0C\u6211\u4EEC\u4F7F\u7528 multiplexer \u53EF\u4EE5\u5F88\u5BB9\u6613\u5730\u5728\u4E00\u4E2A\u767B\u5F55\u7684\u7EC8\u7AEF\u4E2D\u7BA1\u7406\u5927\u91CF\u4F1A\u8BDD\uFF0C\u6BCF\u4E2A\u4F1A\u8BDD\u90FD\u6709\u81EA\u5DF1\u7684shell\u3002\\n\\n\u4E00\u4E2A\u4F1A\u8BDD\u901A\u5E38\u6709 *attached* \u548C *detached* \u4E24\u79CD\u72B6\u6001\uFF0Cattached \u8868\u793A\u6709\u67D0\u4E2A shell \u6B63\u5728\u4F7F\u7528\u5B83\uFF08\u53EF\u4EE5\u540C\u65F6\u4ECE\u591A\u4E2A shell \u8FDB\u5165\u540C\u4E00\u4F1A\u8BDD\uFF09\uFF0Cdetached \u8868\u793A\u5B83\u6CA1\u88AB\u4F7F\u7528\u3002\\n\\n\u5904\u4E8E\u4E00\u4E2A\u4F1A\u8BDD\u4E2D\u65F6\uFF0C\u901A\u5E38\u8981\u4F7F\u7528\u7EC4\u5408\u952E\u6765\u5411 multiplexer \u53D1\u9001\u547D\u4EE4\uFF0C\u89C1\u540E\u7EED\u4ECB\u7ECD\u3002\u5728\u4F1A\u8BDD\u4E2D\uFF0C\u7528\u6237\u53EF\u4EE5\u4F7F\u7528\u7684\u7EC4\u5408\u952E\u901A\u5E38\u90FD\u975E\u5E38\u4E30\u5BCC\uFF0C\u53EF\u4EE5\u5B9E\u73B0\u5728\u540C\u4E00\u4F1A\u8BDD\u4E2D\u521B\u5EFA\u591A\u4E2A\u7A97\u53E3\u3001\u5206\u5C4F\u7B49\u64CD\u4F5C\u3002\\n\\n### screen\\n\\n`screen` \u662FLinux\u901A\u5E38\u4F1A\u5E26\u7684 multiplexer\u3002\u521B\u5EFA\u5E76\u8FDB\u5165\u4F1A\u8BDD\u540E\uFF0C\u6240\u6709\u53D1\u7ED9 `screen` \u7684\u547D\u4EE4\u90FD\u7531\u7EC4\u5408\u952E `Control + a` \u5F00\u5934\u3002\u4F8B\u5982\uFF1A\\n\\n| \u7EC4\u5408\u952E          | \u529F\u80FD                                     |\\n| --------------- | ---------------------------------------- |\\n| Control + a + ? | \u67E5\u770B\u5728`screen`\u4F1A\u8BDD\u4E2D\u53EF\u4F7F\u7528\u7684key bindings |\\n| Control + a + d | detach\uFF0C\u628A\u5F53\u524D\u4F1A\u8BDD\u6302\u5728\u540E\u53F0               |\\n\\n\u5B9E\u9645\u64CD\u4F5C\u7684\u4F8B\u5B50\u5982\u4E0B\uFF1A\\n\\n```bash\\n## \u4EE5detached\u6A21\u5F0F\u521B\u5EFA\u4E00\u4E2A\u6709\u540D\u5B57\u7684\u4F1A\u8BDD\\n$ screen -dmS test\\n\\n## \u521B\u5EFA\u53E6\u4E00\u4E2A\u6709\u540D\u5B57\u7684\u4F1A\u8BDD\uFF0C\u5E76\u7ACB\u5373\u4F7F\u7528\uFF08attach\uFF09\\n$ screen -S develop\\n\\n## \u5217\u51FA\u6240\u6709\u5B58\u5728\u7684\u4F1A\u8BDD\u548C\u72B6\u6001\\n$ screen -ls\\nThere are screens on:\\n        26426.develop   (Attached)\\n        26348.test      (Detached)\\n2 Sockets in /var/run/screen/S-one.\\n\\n## detach\u5F53\u524D\u4F1A\u8BDD\uFF0C\u9000\u56DE\u5230\u6700\u521D\u7684shell\\nControl + a + d\\n\\n## \u8FDB\u5165\u53E6\u4E00\u4E2A\u4F1A\u8BDD\uFF08reattach\uFF09\\n$ screen -r test\\n\\n## \u5047\u8BBE\u7F51\u7EDC\u7A81\u7136\u4E2D\u65AD\uFF0C\u53C8\u6216\u8005\u6211\u4EEC\u60F3\u5728\u53E6\u4E00\u53F0\u7535\u8111\u4E0A\u7EE7\u7EED\u4E4B\u524D\u7684\u5DE5\u4F5C\\n## \u53EA\u9700\u8981\u767B\u5F55\u540E\u6267\u884C\\n$ screen -r develop\\n```\\n\\n### tmux\\n\\n\u53C2\u8003\uFF1A\\n\\n- [Tmux Wiki](https://github.com/tmux/tmux/wiki)\\n\\n- [Tmux Cheat Sheet & Quick Reference](https://tmuxcheatsheet.com/)\\n\\n`tmux` \u662F\u4E00\u4E2A\u6BD4 `screen` \u529F\u80FD\u66F4\u5168\u9762\u7684 multiplexer\uFF0C\u4F46\u5B83\u4EEC\u7684\u57FA\u672C\u7528\u6CD5\u5DEE\u4E0D\u591A\u3002\u521B\u5EFA\u5E76\u8FDB\u5165\u4F1A\u8BDD\u540E\uFF0C\u6240\u6709\u53D1\u7ED9 `screen` \u7684\u547D\u4EE4\u90FD\u7531\u7EC4\u5408\u952E `Control + b` \u5F00\u5934\u3002\u4F8B\u5982\uFF1A\\n\\n| \u7EC4\u5408\u952E            | \u529F\u80FD                                               |\\n| ----------------- | -------------------------------------------------- |\\n| Control + b + ?   | \u67E5\u770B\u5728`tmux`\u4F1A\u8BDD\u4E2D\u53EF\u4F7F\u7528\u7684key bindings\u548C\u547D\u4EE4       |\\n| Control + b + d   | detach\uFF0C\u628A\u5F53\u524D\u4F1A\u8BDD\u6302\u5728\u540E\u53F0                         |\\n| Control + b + :   | \u53D1\u9001\u547D\u4EE4\u5230`tmux`\uFF0C\u6BCF\u4E2A\u7EC4\u5408\u952E\u7684\u529F\u80FD\u90FD\u53EF\u4EE5\u7528\u547D\u4EE4\u5B8C\u6210 |\\n| Control + b + c   | \u5728\u5F53\u524D\u4F1A\u8BDD\u521B\u5EFA\u65B0\u7684window                           |\\n| Control + b + n/p | \u5207\u6362\u5230\u524D\u4E00\u4E2A/\u540E\u4E00\u4E2Awindow                          |\\n| Control + b + w   | \u5217\u51FA\u73B0\u5B58\u7684windows\uFF0C\u53EF\u7528\u952E\u76D8\u4E0A/\u4E0B\u952E\u9009\u62E9             |\\n\\n\u5B9E\u9645\u64CD\u4F5C\u7684\u4F8B\u5B50\u5982\u4E0B\uFF1A\\n\\n```bash\\n## \u4EE5detached\u6A21\u5F0F\u521B\u5EFA\u4E00\u4E2A\u6709\u540D\u5B57\u7684\u4F1A\u8BDD\\n$ tmux new-session -ds test\\n\\n## \u521B\u5EFA\u53E6\u4E00\u4E2A\u6709\u540D\u5B57\u7684\u4F1A\u8BDD\uFF0C\u5E76\u7ACB\u5373\u4F7F\u7528\uFF08attach\uFF09\\n$ tmux new-session -s develop\\n\\n## \u5217\u51FA\u6240\u6709\u5B58\u5728\u7684\u4F1A\u8BDD\u548C\u72B6\u6001\\n$ tmux ls\\ntest: 1 windows\\ndevelop: 1 windows (attached)\\n\\n## detach\u5F53\u524D\u4F1A\u8BDD\uFF0C\u9000\u56DE\u5230\u6700\u521D\u7684shell\\nControl + b + d\\n\\n## \u8FDB\u5165\u53E6\u4E00\u4E2A\u4F1A\u8BDD\uFF08reattach\uFF09\\n$ tmux attach -t test\\n\\n## \u5047\u8BBE\u7F51\u7EDC\u7A81\u7136\u4E2D\u65AD\uFF0C\u53C8\u6216\u8005\u6211\u4EEC\u60F3\u5728\u53E6\u4E00\u53F0\u7535\u8111\u4E0A\u7EE7\u7EED\u4E4B\u524D\u7684\u5DE5\u4F5C\\n## \u53EA\u9700\u8981\u767B\u5F55\u540E\u6267\u884C\\n$ tmux attach -t develop\\n```\\n\\n## \u4FDD\u6301SSH\u6216SFTP\u8FDE\u63A5\\n\\n\u5F53\u6211\u4EEC\u4F7F\u7528\u96C6\u7FA4\u65F6\uFF0C\u4F7F\u7528 `screen` \u6216 `tmux` \u8FD9\u6837\u7684\u7A0B\u5E8F\u80FD\u8BA9\u6211\u4EEC\u4FDD\u5B58\u5F53\u524D\u7684\u5DE5\u4F5C\u4EE5\u4FBF\u4E0B\u6B21\u7EE7\u7EED\u3002\u5982\u679C\u51FA\u4E8E\u67D0\u79CD\u7406\u7531\u6211\u4EEC\u4E0D\u5E0C\u671B\u53CD\u590D\u767B\u5F55\u96C6\u7FA4\uFF08\u6BD4\u5982\u9700\u8981\u52A8\u6001\u53E3\u4EE4\uFF09\uFF0C\u90A3\u5C31\u9700\u8981\u4FDD\u5B58\u5DF2\u767B\u5F55\u7684 shell\uFF0C\u4E5F\u5C31\u662F\u5728 multiplexer \u6253\u5F00\u7684\u4F1A\u8BDD\u91CC\u9762\u767B\u5F55\u96C6\u7FA4\u3002\\n\\n\u4F8B\u5982\uFF0C\u6211\u4EEC\u60F3\u5728\u5B9E\u9A8C\u5BA4\u673A\u5668\u4E0A\u521B\u5EFA\u4F1A\u8BDD\uFF0C\u5728\u8FD9\u4E2A\u4F1A\u8BDD\u91CC\u9762\u6253\u5F00\u4E00\u4E2ASSH\u548C\u4E00\u4E2ASFTP\u5230\u67D0\u8D85\u7B97S\u3002\u5047\u8BBE\u8D85\u7B97\u57DF\u540D\u662F `s.example.cn`\uFF0C\u7AEF\u53E3\u662F `12345`\uFF0C\u6211\u7684\u7528\u6237\u540D\u662F `hpcer`\u3002\\n\\n```bash\\n## \u9996\u5148\u4ECE\u81EA\u5DF1\u7535\u8111\u767B\u5F55\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\\n$ ssh hpcer@ssh.hpcer.dev\\n\\n## \u521B\u5EFA\u4E00\u4E2Atmux\u4F1A\u8BDD\u7528\u4E8ESSH\\n$ tmux new-session -s myssh\\n\\n## \u5728myssh\u4F1A\u8BDD\u4E2D\u8FDE\u63A5\u8D85\u7B97S\\n$ ssh -o ServerAliveInterval=60 -p 12345 hpcer@s.example.cn\\n\\n## \u7528\u7EC4\u5408\u952Edetach\u5F53\u524D\u4F1A\u8BDD\\nControl + b + d\\n\\n## \u521B\u5EFA\u53E6\u4E00\u4E2Atmux\u4F1A\u8BDD\u7528\u4E8ESFTP\\n$ tmux new-session -s mysftp\\n\\n## \u5728mysftp\u4F1A\u8BDD\u4E2D\u8FDE\u63A5\u8D85\u7B97S\\n$ sftp -o ServerAliveInterval=60 -P 12345 hpcer@s.example.cn\\n\\n## \u7528\u7EC4\u5408\u952Edetach\u5F53\u524D\u4F1A\u8BDD\\nControl + b + d \\n```\\n\\n\u521B\u5EFA\u4E86\u4E0A\u8FF0\u4E24\u4E2A\u4F1A\u8BDD\u540E\uFF0C\u53EA\u8981\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\u5230\u8D85\u7B97S\u7684\u8FDE\u63A5\u4E0D\u65AD\u5F00\uFF0C\u6211\u4EEC\u968F\u65F6\u90FD\u53EF\u4EE5\u901A\u8FC7 `tmux` \u4F1A\u8BDD\u56DE\u5230\u8D85\u7B97S\uFF0C\u4E0D\u9700\u8981\u53CD\u590D\u767B\u5F55\u3002\u5982\u679C\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\u5230\u8D85\u7B97S\u7684\u8FDE\u63A5\u4E5F\u4E0D\u7A33\u5B9A\uFF0C\u53EF\u4EE5\u6362\u5176\u4ED6\u4E0D\u5728\u6821\u56ED\u7F51\u7684\u673A\u5668\u3002"},{"id":"one-bout-dev-usage","metadata":{"permalink":"/cluster-docs/blog/one-bout-dev-usage","editUrl":"https://github.com/hpcde/cluster-docs/blob/master/blog/2020-12-11-one-bout-dev-usage.md","source":"@site/blog/2020-12-11-one-bout-dev-usage.md","title":"\u4F7F\u7528\u96C6\u7FA4\u4E0A\u5B89\u88C5\u7684BOUT++\u5E93","description":"\u672C\u6587\u6F14\u793A\u4E86\u5982\u4F55\u4F7F\u7528\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\u4E0A\u5B89\u88C5\u7684BOUT++\u3002","date":"2020-12-11T00:00:00.000Z","tags":[{"inline":true,"label":"tutorial","permalink":"/cluster-docs/blog/tags/tutorial"},{"inline":true,"label":"bout++","permalink":"/cluster-docs/blog/tags/bout"},{"inline":true,"label":"spack","permalink":"/cluster-docs/blog/tags/spack"}],"readingTime":2.99,"hasTruncateMarker":true,"authors":[{"name":"Wang An","title":"PhD student at USTB","url":"https://github.com/alephpiece","page":{"permalink":"/cluster-docs/blog/authors/one"},"imageURL":"https://github.com/alephpiece.png","key":"one"}],"frontMatter":{"slug":"one-bout-dev-usage","title":"\u4F7F\u7528\u96C6\u7FA4\u4E0A\u5B89\u88C5\u7684BOUT++\u5E93","authors":"one","tags":["tutorial","bout++","spack"]},"unlisted":false,"prevItem":{"title":"\u5B9E\u7528\u5DE5\u5177\uFF1ATerminal Multiplexers","permalink":"/cluster-docs/blog/one-terminal-multiplexers"},"nextItem":{"title":"\u5207\u6362Spack\u73AF\u5883\u53D8\u91CF","permalink":"/cluster-docs/blog/one-reset-spack-env"}},"content":"\u672C\u6587\u6F14\u793A\u4E86\u5982\u4F55\u4F7F\u7528\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\u4E0A\u5B89\u88C5\u7684BOUT++\u3002\\n\\n\u4F7F\u7528\u5DF2\u5B89\u88C5\u7684\u67D0\u7248\u672CBOUT++\u5E93\uFF1A\\n\\n```bash\\n$ spack load bout-dev ~openmp+scorep\\n```\\n\\n\u4F7F\u7528BOUT++\u7684\u4F9D\u8D56\uFF0C\u4F46\u4E0D\u5305\u62ECBOUT++\u5E93\u672C\u8EAB\uFF1A\\n\\n```bash\\n$ spack load --only dependencies ~openmp+scorep\\n```\\n\\n\u67E5\u770B\u5F53\u524DBOUT++\u7684\u914D\u7F6E\uFF1A\\n```bash\\n$ bout-config --all\\n```\\n\\n{/* truncate */}\\n\\n## \u94FE\u63A5\u96C6\u7FA4\u4E0A\u5DF2\u5B89\u88C5\u7684BOUT++\u5E93\\n\\nBOUT++\u901A\u5E38\u9700\u8981\u5F00\u53D1\u8005\u5728\u6E90\u4EE3\u7801\u76EE\u5F55\u4E0B\u7F16\u8BD1\uFF0C\u4E5F\u5C31\u662F*in-source build*\u3002\u5B8C\u6210build\u540E\u6709\u4EE5\u4E0B\u51E0\u4E2A\u6BD4\u8F83\u91CD\u8981\u7684\u6587\u4EF6\uFF1A\\n\\n- `lib/libbout++.a`\uFF1ABOUT++\u7684\u9759\u6001\u5E93\uFF0C\u9ED8\u8BA4\u662F\u6CA1\u6709\u5171\u4EAB\u5E93\u7684\uFF1B\\n- `bin/bout-config`\uFF1A\u6253\u5370BOUT++\u914D\u7F6E\u4FE1\u606F\u7684\u811A\u672C\uFF0C\u6BD4\u5982\u5E93\u7684\u8DEF\u5F84\u3001\u7F16\u8BD1\u5668\u8DEF\u5F84\u7B49\uFF1B\\n- `make.config`\uFF1A\u7F16\u8BD1BOUT++\u7B97\u4F8B\u7528\u7684makefile\uFF0C\u5305\u542B\u5934\u6587\u4EF6\u548C\u5E93\u8DEF\u5F84\u3001\u7F16\u8BD1flags\u7B49\u3002\\n\\n\u968F\u540E\u6211\u4EEC\u53EF\u4EE5\u8FDB\u5230\u7B97\u4F8B\u7684\u76EE\u5F55\u4E0B\uFF0C\u76F4\u63A5\u8C03`make`\u6765\u7F16\u8BD1\u7B97\u4F8B\u5F97\u5230\u53EF\u6267\u884C\u6587\u4EF6\uFF0C\u4F8B\u5982\\n\\n```bash\\n$ cd examples/conduction\\n$ make\\n```\\n\\n\u7B97\u4F8B\u76EE\u5F55\u4E0B\u7684makefile\u4F1A\u5C06BOUT++\u7684\u6839\u76EE\u5F55`BOUT_TOP`\u8BBE\u7F6E\u4E3A\u5F53\u524D\u6E90\u4EE3\u7801\u7684\u6839\u76EE\u5F55\uFF0C\u7136\u540E\u8C03`make.config`\u5B8C\u6210\u540E\u7EED\u5DE5\u4F5C\u3002\\n\\n`make.config`\u4E2D\u7684\u5173\u952E\u53D8\u91CF\u662F\u5728\u7528\u6237\u914D\u7F6EBOUT++\u7684\u8FC7\u7A0B\u4E2D\u8BBE\u7F6E\u7684\uFF0C\u548C\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\u4E0A\u5B89\u88C5\u7684BOUT++\u4E0D\u4E00\u6837\u3002\u56E0\u6B64\uFF0C\u8981\u94FE\u63A5\u96C6\u7FA4\u4E0A\u5B89\u88C5\u7684BOUT++\u5E93\uFF0C\u6211\u4EEC\u5C31\u4E0D\u80FD\u76F4\u63A5\u7528\u7B97\u4F8B\u76EE\u5F55\u4E0B\u73B0\u6709\u7684makefile\uFF0C\u9700\u8981\u6309\u7167BOUT++\u5B98\u7F51\u7684\u8BF4\u660E\u4FEE\u6539makefile\u3002\\n\\n\u4EE5`examples/conduction/makefile`\u4E3A\u4F8B\u94FE\u63A5\u5B9E\u9A8C\u5BA4\u96C6\u7FA4\u4E0A\u5B89\u88C5\u7684BOUT++\u5E93\uFF1A\\n\\n```bash\\n## \u52A0\u8F7DSpack\u73AF\u5883\\n$ source /apps/spack/share/spack/setup-env.sh\\n\\n## \u52A0\u8F7DBOUT++\uFF0C\u5982\u679C\u6709\u591A\u4E2ABOUT++\u5305\uFF0C\u8BF7\u6309\u7167\u96C6\u7FA4\u6587\u6863\u4E2DSpack\u4F7F\u7528\u8BF4\u660E\u6765\u7B5B\u9009\\n## \u6700\u7EC8\u63D0\u4EA4\u811A\u672C\u5230\u96C6\u7FA4\u8FD0\u884C\u7B97\u4F8B\u65F6\uFF0C\u4E5F\u8981\u7528\u8FD9\u4E00\u53E5\u6765\u52A0\u8F7D\u73AF\u5883\\n$ spack load bout-dev +openmp+scorep\\n\\n## \u76EE\u524D\uFF0C\u5728\u96C6\u7FA4\u4E0A\u5B89\u88C5\u7684BOUT++\u81F3\u5C11\u6709OpenMP\u548C\u975EOpenMP\u4E24\u4E2A\u7248\u672C\\n## spack load bout-dev ~openmp+scorep\\n\\n## \u8FDB\u5165\u81EA\u5DF1\u4E0B\u8F7D\u7684BOUT++\u7B97\u4F8B\u76EE\u5F55\\n$ cd BOUT-dev/examples/conduction\\n\\n## \u4FEE\u6539makefile\uFF0C\u65B0makefile\u7684\u4F8B\u5B50\u5728examples/make-script\u4E2D\\n$ sed -e \'s/test.cxx/conduction.cxx/g\' ../make-script/makefile > makefile\\n\\n## \u521B\u5EFA\u53EF\u6267\u884C\u6587\u4EF6\\n$ make clean && make\\n```\\n\\n\u6267\u884C\u4E0A\u8FF0\u547D\u4EE4\u540E\uFF0C\u6211\u4EEC\u5C31\u5F97\u5230\u4E86\u7B97\u4F8B\u7684\u53EF\u6267\u884C\u6587\u4EF6`conduction`\u3002\\n\\n\u82E5\u8981\u4F7F\u7528BOUT++\u6E90\u4EE3\u7801\u76EE\u5F55\u4E0B\u7684Python\u5305\uFF0C\u6709\u4E24\u79CD\u9009\u62E9\uFF1A\u7528\u81EA\u5DF1\u4E0B\u8F7D\u7684\uFF0C\u6216\u7528\u96C6\u7FA4\u4E0A\u5DF2\u5B89\u88C5\u7684\u3002\u81EA\u5DF1\u4E0B\u8F7D\u7684\u53EF\u53C2\u8003\u6587\u540E\u7684\u94FE\u63A5\u3002\u4E0B\u9762\u6F14\u793A\u5982\u4F55\u4F7F\u7528\u96C6\u7FA4\u4E0A\u5DF2\u6709\u7684\u3002\\n\\n```bash\\n## \u52A0\u8F7D\u96C6\u7FA4\u7684BOUT++\u5305\\n$ spack load bout-dev +openmp+scorep\\n\\n## \u4F7F\u7528bout-config\u83B7\u53D6Python\u5305\u8DEF\u5F84\u5E76\u6DFB\u52A0\u5230\u73AF\u5883\u53D8\u91CF\u4E2D\\n$ export PYTHONPATH=$(bout-config --python):$PYTHONPATH\\n```\\n\\n\u6267\u884C\u4E0A\u8FF0\u547D\u4EE4\u540E\uFF0C\u4FBF\u53EF\u5728\u4F7F\u7528Python\u65F6\u5BFC\u5165BOUT++\u7684Python\u5305\u3002\\n\\n## \u4F7F\u7528\u96C6\u7FA4\u4E0A\u5B89\u88C5\u7684\u4F9D\u8D56\u9879\u7F16\u8BD1BOUT++\\n\\n\u5F53\u6211\u4EEC\u60F3\u91CD\u65B0\u7F16\u8BD1BOUT++\u65F6\uFF0C\u53EF\u4EE5\u4F7F\u7528\u96C6\u7FA4\u4E0A\u5B89\u88C5\u7684BOUT++\u4F9D\u8D56\u9879\uFF0C\u901A\u5E38\u4E0D\u9700\u8981\u81EA\u5DF1\u518D\u6B21\u5B89\u88C5\u3002\u6D89\u53CASpack\u7684\u64CD\u4F5C\u53EF\u53C2\u8003\u96C6\u7FA4\u6587\u6863\u4E2DSpack\u7684\u8BF4\u660E\u3002\\n\\n```bash\\n## \u52A0\u8F7DBOUT++\u7684\u4F9D\u8D56\u9879\uFF0C\u4F46\u4E0D\u52A0\u8F7DBOUT++\u672C\u8EAB\\n$ spack load --only dependencies bout-dev ~openmp+scorep\\n\\n## \u8FDB\u5165\u81EA\u5DF1\u4E0B\u8F7D\u7684BOUT++\u76EE\u5F55\\n$ cd BOUT-dev\\n\\n## \u6309\u7167\u81EA\u5DF1\u7684\u9700\u8981\u5B8C\u6210build\\n$ ./configure --with-petsc --with-sundials && make -j16\\n```\\n\\n## \u53C2\u8003\u8D44\u6599\\n\\n- [BOUT++ - Getting started](https://bout-dev.readthedocs.io/en/latest/user_docs/installing.html)\\n- [BOUT++ - Python configuration](https://bout-dev.readthedocs.io/en/latest/user_docs/installing.html#python-configuration)\\n- [BOUT++ - Installing BOUT++(experimental)](https://bout-dev.readthedocs.io/en/latest/user_docs/installing.html#installing-bout-experimental)"},{"id":"one-reset-spack-env","metadata":{"permalink":"/cluster-docs/blog/one-reset-spack-env","editUrl":"https://github.com/hpcde/cluster-docs/blob/master/blog/2020-12-11-one-reset-spack-env.md","source":"@site/blog/2020-12-11-one-reset-spack-env.md","title":"\u5207\u6362Spack\u73AF\u5883\u53D8\u91CF","description":"Spack\u7684\u73AF\u5883\u53D8\u91CF\u3001\u81EA\u52A8\u8865\u5168\u7B49\u90FD\u7531Spack\u76EE\u5F55\u4E0B\u7684\u811A\u672C\u8BBE\u7F6E\u3002\u4F8B\u5982\uFF0C\u4E3Abash\u8BBE\u7F6E\u73AF\u5883\u53D8\u91CF\u7684\u547D\u4EE4\u4E3A","date":"2020-12-11T00:00:00.000Z","tags":[{"inline":true,"label":"tutorial","permalink":"/cluster-docs/blog/tags/tutorial"},{"inline":true,"label":"spack","permalink":"/cluster-docs/blog/tags/spack"}],"readingTime":2.64,"hasTruncateMarker":true,"authors":[{"name":"Wang An","title":"PhD student at USTB","url":"https://github.com/alephpiece","page":{"permalink":"/cluster-docs/blog/authors/one"},"imageURL":"https://github.com/alephpiece.png","key":"one"}],"frontMatter":{"slug":"one-reset-spack-env","title":"\u5207\u6362Spack\u73AF\u5883\u53D8\u91CF","authors":"one","tags":["tutorial","spack"]},"unlisted":false,"prevItem":{"title":"\u4F7F\u7528\u96C6\u7FA4\u4E0A\u5B89\u88C5\u7684BOUT++\u5E93","permalink":"/cluster-docs/blog/one-bout-dev-usage"},"nextItem":{"title":"\u4E00\u4E9B\u6709\u7528\u7684\u53C2\u8003\u8D44\u6599","permalink":"/cluster-docs/blog/helpful-links"}},"content":"Spack\u7684\u73AF\u5883\u53D8\u91CF\u3001\u81EA\u52A8\u8865\u5168\u7B49\u90FD\u7531Spack\u76EE\u5F55\u4E0B\u7684\u811A\u672C\u8BBE\u7F6E\u3002\u4F8B\u5982\uFF0C\u4E3Abash\u8BBE\u7F6E\u73AF\u5883\u53D8\u91CF\u7684\u547D\u4EE4\u4E3A\\n\\n```bash\\n$ export SPACK_ROOT=/path/to/spack\\n$ source $SPACK_ROOT/share/spack/setup-env.sh\\n```\\n\\n\u5F53\u6211\u4EEC\u6709\u591A\u4E2ASpack\u65F6\uFF0C\u76F4\u63A5`source`\u5176\u4E2D\u4E00\u4E2ASpack\u7684\u73AF\u5883\u914D\u7F6E\u811A\u672C\u53EF\u80FD\u4E0D\u4F1A\u8FBE\u5230\u9884\u671F\u6548\u679C\u3002\u6BD4\u5982\uFF0C\u9996\u5148\u52A0\u8F7D\u4E86\u96C6\u7FA4\u7684\u516C\u5171Spack\uFF0C\u968F\u540E\u5207\u6362\u5230\u81EA\u5DF1\u7684\u672C\u5730Spack\uFF0C\u5B9E\u9645\u4E0A\u4ECD\u6709\u4E9B\u73AF\u5883\u662F\u516C\u5171Spack\u8BBE\u7F6E\u7684\u3002\u6B64\u65F6\u6211\u4EEC\u9700\u8981\u6E05\u9664\u4E00\u4E0B\u65E7\u7684\u73AF\u5883\u3002\\n\\n{/* truncate */}\\n\\n> \u4EE5\u4E0B\u5747\u4EE5bash\u4E3A\u4F8B\u3002\\n\\n## Spack\u7684\u73AF\u5883\u53D8\u91CF\\n\\nSpack\u7684\u73AF\u5883\u914D\u7F6E\u811A\u672C`setup-env.sh`\u5B9E\u9645\u4E0A\u4F1A\u5982\u4E0B\u4FEE\u6539\u7528\u6237\u7684\u73AF\u5883\uFF1A\\n\\n- \u4FEE\u6539\u53D8\u91CF`SPACK_ROOT`\uFF1B\\n- \u4FEE\u6539\u53D8\u91CF`PATH`\uFF0C\u6DFB\u52A0`$SPACK_ROOT/bin`\uFF0C\u4F46\u8BE5\u76EE\u5F55\u5DF2\u5B58\u5728\u65F6\u4F1A\u8DF3\u8FC7\u4FEE\u6539\uFF1B\\n- \u5B9A\u4E49\u51FD\u6570`_spack_shell_wrapper`\uFF0C\u662F\u5904\u7406Spack\u547D\u4EE4\u7684\u51FD\u6570\uFF1B\\n- \u5B9A\u4E49\u51FD\u6570`spack`\uFF0C\u662F\u7ED9\u7528\u6237\u4F7F\u7528\u7684\u3002\\n\\n\u5982\u679C\u4EE5\u4E0A\u73AF\u5883\u90FD\u5DF2\u88AB\u8BBE\u7F6E\uFF0C\u518D`source`\u53E6\u4E00\u4E2A\u8DEF\u5F84\u4E0B\u7684Spack\uFF0C\u5F88\u53EF\u80FD\u53EA\u6709`SPACK_ROOT`\u88AB\u4FEE\u6539\u3002\u6B64\u65F6\u7528\u6237\u4F7F\u7528`which spack`\u7B49\u547D\u4EE4\u90FD\u53EA\u80FD\u627E\u5230\u65E7\u7684\u53D8\u91CF\u548C\u51FD\u6570\u3002\u5C24\u5176\u662F\uFF0C\u5982\u679C`PATH`\u6CA1\u6709\u6B63\u786E\u88AB\u4FEE\u6539\uFF0C\u7528\u6237\u5B9E\u9645\u6267\u884C\u7684\u53EF\u6267\u884C\u6587\u4EF6\u4ECD\u7136\u6765\u81EA\u4E8E\u65E7\u8DEF\u5F84\u3002\\n\\n## \u91CD\u7F6ESpack\u7684\u73AF\u5883\\n\\n\u5207\u6362Spack\u6700\u5E72\u51C0\u7684\u65B9\u6CD5\u5C31\u662F\u91CD\u65B0\u5F00shell\uFF0C\u91CD\u65B0`source`\u914D\u7F6E\u811A\u672C\u3002\u5982\u679C\u4E00\u5B9A\u8981\u5728\u5F53\u524Dshell\u5207\u6362Spack\uFF0C\u53EF\u4EE5\u624B\u52A8\u5220\u9664\u65E7\u7684\u73AF\u5883\u53D8\u91CF`PATH`\u548C\u51FD\u6570`_spack_shell_wrapper`\u3001`spack`\u3002\u5982\u679CSpack\u7248\u672C\u5DEE\u7684\u4E0D\u591A\uFF0C\u5B9E\u9645\u4E0A\u53EA\u9700\u8981\u4FEE\u6539`PATH`\u5C31\u5DEE\u4E0D\u591A\u80FD\u6B63\u5E38\u4F7F\u7528\u3002\\n\\n\u4E0B\u9762\u63D0\u4F9B\u4E00\u4E2A\u53EF\u4EE5\u5220\u9664\u8FD9\u4E9B\u73AF\u5883\u7684\u811A\u672C\u3002\u8BE5\u811A\u672C\u7684\u8F93\u5165\u53C2\u6570\u4E3ASpack\u7684`setup-env.sh`\u8DEF\u5F84\u3002\\n\\n```bash\\n#   Script:\\n#       reset-env.sh\\n#   Usage:\\n#       source ./reset-env.sh /path/to/setup-env.sh\\n#\\n#!/bin/bash\\n\\nunset_spack_path() {\\n    # Figure out Spack paths\\n    local spack_script=$1\\n    local spack_share_dir=\\"$(cd \\"$(dirname $spack_script)\\" > /dev/null && pwd)\\"\\n    local spack_prefix=\\"$(cd \\"$(dirname $(dirname $spack_share_dir))\\" > /dev/null && pwd)\\"\\n    local spack_bin=\\"${spack_prefix%/}/bin\\"\\n\\n    # Remove the specified directory from PATH\\n    local path_old=$PATH\\n    local path_canonical=\\":$path_old:\\"\\n\\n    if [[ \\"$path_canonical\\" =~ \\":$spack_bin:\\" ]];\\n    then\\n        # Remove the given directory\\n        local path_new=\\"${spack_bin}${path_canonical//:$spack_bin:/:}\\"\\n\\n        # Remove the tail colon\\n        path_new=${path_new%:}\\n\\n        # Export PATH, this will change the user environment\\n        export PATH=$path_new\\n\\n        echo \\"removed from PATH: $spack_bin\\"\\n    else\\n        echo \\"removed nothing\\"\\n    fi\\n}\\n\\nunset_spack_func() {\\n    # Spack functions\\n    local spack_functions=(spack _spack_shell_wrapper)\\n\\n    for i in \\"${spack_functions[@]}\\"\\n    do\\n        if [ -n $i ] && [ \\"$(type -t $i)\\" = function ]\\n        then\\n            # This is supposed to change the user environment\\n            unset -f $i\\n            echo \\"unset function: $i\\"\\n        else\\n            echo \\"$i not found\\"\\n        fi\\n    done\\n}\\n\\necho -e \\"\\\\nRemoving Spack directory from PATH...\\"\\nunset_spack_path \\"$1\\"\\n\\necho -e \\"\\\\nUnsetting Spack functions...\\"\\nunset_spack_func\\n\\necho -e \\"\\\\nSourcing ${1}...\\"\\nsource \\"$1\\" &> /dev/null\\nif [ $? != 0 ]; then\\n    echo \\"failed to source $1\\"\\nfi\\n\\necho -e \\"\\\\nNow, you can run following commands for checking\\"\\necho -e \\"\\\\t$ which spack\\"\\necho -e \\"\\\\t$ env | grep -i spack\\"\\n```\\n\\n\u8BE5\u811A\u672C\u9700\u8981`source`\uFF0C\u4F7F\u7528\u65B9\u5F0F\u5982\u4E0B\\n```bash\\nexport SPACK_ROOT=/path/to/new/spack\\n$ source ./reset-env.sh $SPACK_ROOT/share/spack/setup-env.sh\\n```\\n\\n\u811A\u672C\u4E2D\u7684`unset_spack_path`\u7528\u4E8E\u8BA1\u7B97\u4E00\u4E9B\u8DEF\u5F84\u5E76\u4FEE\u6539\u7528\u6237\u7684`PATH`\uFF0C\u6267\u884C\u5B8C\u540E\uFF0C\u7528\u6237\u63D0\u4F9B\u7684\u65B0Spack\u7684\u8DEF\u5F84\u4F1A\u5E76\u52A0\u5230`PATH`\u6700\u524D\u9762\u3002`unset_spack_func`\u7528\u4E8E\u6E05\u9664\u65E7\u7684\u51FD\u6570\u3002"},{"id":"helpful-links","metadata":{"permalink":"/cluster-docs/blog/helpful-links","editUrl":"https://github.com/hpcde/cluster-docs/blob/master/blog/2020-11-25-helpful-links.md","source":"@site/blog/2020-11-25-helpful-links.md","title":"\u4E00\u4E9B\u6709\u7528\u7684\u53C2\u8003\u8D44\u6599","description":"\u8FD9\u91CC\u63D0\u4F9B\u4E00\u4E9B\u6709\u7528\u7684\u53C2\u8003\u8D44\u6599, \u4E3B\u8981\u662F\u5173\u4E8E Slurm \u7CFB\u7EDF\u3001Linux\u3001DCU/GPU\u3001\u7F16\u8BD1\u8C03\u8BD5\u76F8\u5173\u7684\u5185\u5BB9\u3002","date":"2020-11-25T00:00:00.000Z","tags":[{"inline":false,"label":"Hello","permalink":"/cluster-docs/blog/tags/hello","description":"Hello tag description"}],"readingTime":0.63,"hasTruncateMarker":false,"authors":[{"name":"Genshen Chu","title":"Teacher at USTB","url":"https://github.com/genshen","page":{"permalink":"/cluster-docs/blog/authors/genshen"},"imageURL":"https://secure.gravatar.com/avatar/15520bc606e6177300abacab337a5dc6?s=800&d=identicon","key":"genshen"}],"frontMatter":{"slug":"helpful-links","title":"\u4E00\u4E9B\u6709\u7528\u7684\u53C2\u8003\u8D44\u6599","authors":"genshen","tags":["hello"]},"unlisted":false,"prevItem":{"title":"\u5207\u6362Spack\u73AF\u5883\u53D8\u91CF","permalink":"/cluster-docs/blog/one-reset-spack-env"}},"content":"\u8FD9\u91CC\u63D0\u4F9B\u4E00\u4E9B\u6709\u7528\u7684\u53C2\u8003\u8D44\u6599, \u4E3B\u8981\u662F\u5173\u4E8E Slurm \u7CFB\u7EDF\u3001Linux\u3001DCU/GPU\u3001\u7F16\u8BD1\u8C03\u8BD5\u76F8\u5173\u7684\u5185\u5BB9\u3002  \\n\u76F8\u5173\u8D44\u6599\u4F1A\u4E0D\u5B9A\u671F\u66F4\u65B0\u3002\\n\\n### HPC \u7406\u8BBA\\n- [Introduction to Parallel Computing](https://computing.llnl.gov/tutorials/parallel_comp/)\\n\\n### Slurm\\n- [SLURM\u8C03\u5EA6\u5668\u57FA\u7840\u6559\u7A0B: \u66D9\u5149\u5148\u8FDB\u8BA1\u7B97](https://www.hpccube.com/wiki/index.php/SLURM\u4F7F\u7528\u57FA\u7840\u6559\u7A0B)\\n- [Research Computing University of Colorado Boulder](https://curc.readthedocs.io/en/latest/running-jobs/slurm-commands.html)\\n\\n### Linux\\n- [Linux\u547D\u4EE4\u5927\u5168](https://man.linuxde.net)\\n- [\u9CE5\u54E5\u7684 Linux \u79C1\u623F\u83DC](https://linux.vbird.org)\\n\\n### \u8C03\u8BD5\\n- [GDB to LLDB command map](https://lldb.llvm.org/use/map.html)\\n\\n### \u7F16\u8F91\u5668\\n- [Vim \u4ECE\u5165\u95E8\u5230\u7CBE\u901A-\u4E2D\u6587](https://github.com/wsdjeg/vim-galore-zh_cn)\\n- [Learn-Vim](https://github.com/iggredible/Learn-Vim)\\n\\n### \u76F8\u5173\u94FE\u63A5\\n- [\u4E0A\u6D77\u4EA4\u901A\u5927\u5B66 Pi \u8D85\u7B97\u96C6\u7FA4\u6587\u6863](https://docs.hpc.sjtu.edu.cn)"}]}}')}}]);